const items = $input.all();
let rows = '';

// Count summary
let total = items.length;
let critical = items.filter(i => i.json.fields.Status === 'CRITICAL').length;
let low = items.filter(i => i.json.fields.Status === 'LOW').length;
let healthy = items.filter(i => i.json.fields.Status === 'GOOD').length;
let expired = items.filter(i => i.json.fields['Expiry Status'] === 'EXPIRED').length;
let expiringSoon = items.filter(i => i.json.fields['Expiry Status'] === 'EXPIRING SOON').length;

// Expiry alert list
let expiryItems = items
  .filter(i => ['EXPIRED', 'EXPIRING SOON'].includes(i.json.fields['Expiry Status']))
  .map(i => `<li>${i.json.fields['Item Name']} — <b>${i.json.fields['Expiry Status']}</b> (${i.json.fields['Expiry Date'] || 'No Date'})</li>`)
  .join('');

items.forEach(item => {
  const f = item.json.fields;
  const statusColor =
    f.Status === 'CRITICAL' ? '#ff0000' :
    f.Status === 'LOW' ? '#ff8c00' : '#008000';
  const expiryColor =
    f['Expiry Status'] === 'EXPIRED' ? '#ff0000' :
    f['Expiry Status'] === 'EXPIRING SOON' ? '#ff8c00' : '#008000';
  rows += `
    <tr>
      <td style="padding:8px;border:1px solid #ddd">${f['Item Name']}</td>
      <td style="padding:8px;border:1px solid #ddd">${f['Current Stock']} ${f['Unit']}</td>
      <td style="padding:8px;border:1px solid #ddd">${f['Minimum Threshold']} ${f['Unit']}</td>
      <td style="padding:8px;border:1px solid #ddd">${f['Supplier']}</td>
      <td style="padding:8px;border:1px solid #ddd;color:${statusColor};font-weight:bold">${f.Status}</td>
      <td style="padding:8px;border:1px solid #ddd;color:${expiryColor};font-weight:bold">${f['Expiry Status'] || 'No Date'}</td>
    </tr>
  `;
});

const html = `
<h2 style="color:#2c3e50">📋 Weekly Lab Inventory Report</h2>

<div style="background:#f5f5f5;padding:12px;border-radius:6px;margin-bottom:16px">
  <h3 style="margin:0 0 8px 0">📊 Inventory Summary</h3>
  <p style="margin:4px 0">Total Items: <b>${total}</b></p>
  <p style="margin:4px 0;color:#ff0000">Critical Stock: <b>${critical}</b></p>
  <p style="margin:4px 0;color:#ff8c00">Low Stock: <b>${low}</b></p>
  <p style="margin:4px 0;color:#008000">Healthy Items: <b>${healthy}</b></p>
  <p style="margin:4px 0;color:#ff0000">Expired Items: <b>${expired}</b></p>
  <p style="margin:4px 0;color:#ff8c00">Expiring Soon: <b>${expiringSoon}</b></p>
</div>

<p>Here is your complete inventory status for this week:</p>
<table style="border-collapse:collapse;width:100%">
  <tr style="background:#2c3e50;color:white">
    <th style="padding:8px;border:1px solid #ddd">Item</th>
    <th style="padding:8px;border:1px solid #ddd">Current Stock</th>
    <th style="padding:8px;border:1px solid #ddd">Minimum Required</th>
    <th style="padding:8px;border:1px solid #ddd">Supplier</th>
    <th style="padding:8px;border:1px solid #ddd">Stock Status</th>
    <th style="padding:8px;border:1px solid #ddd">Expiry Status</th>
  </tr>
  ${rows}
</table>

<br>
<div style="background:#ffe0e0;padding:12px;border-radius:6px">
  <p style="margin:0"><b>🧪 Expiry Alerts:</b></p>
  <ul>${expiryItems}</ul>
</div>

<br>
<p style="color:gray;font-size:12px"><i>Weekly report by Lab Inventory System</i></p>
`;

return [{ json: { html } }];
